import 'package:flutter/material.dart';
class SettingsSection extends StatelessWidget { const SettingsSection({required this.title, required this.child, super.key}); final String title; final Widget child; @override Widget build(BuildContext context) => Card(child: Padding(padding: const EdgeInsets.all(16), child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [Text(title, style: Theme.of(context).textTheme.titleMedium), const SizedBox(height: 8), child]))); }
